695 bool llvm::simplifyLoop(Loop *L, DominatorTree *DT, LoopInfo *LI,
696                         ScalarEvolution *SE, AssumptionCache *AC,
697                         MemorySSAUpdater *MSSAU, bool PreserveLCSSA) {
698   bool Changed = false;
699 
700 #ifndef NDEBUG
701   // If we're asked to preserve LCSSA, the loop nest needs to start in LCSSA
702   // form.
703   if (PreserveLCSSA) {
704     assert(DT && "DT not available.");
705     assert(LI && "LI not available.");
706     assert(L->isRecursivelyLCSSAForm(*DT, *LI) &&
707            "Requested to preserve LCSSA, but it's already broken.");
708   }
709 #endif
710 
711   // Worklist maintains our depth-first queue of loops in this nest to process.
712   SmallVector<Loop *, 4> Worklist;
713   Worklist.push_back(L);
714 
715   // Walk the worklist from front to back, pushing newly found sub loops onto
716   // the back. This will let us process loops from back to front in depth-first
717   // order. We can use this simple process because loops form a tree.
718   for (unsigned Idx = 0; Idx != Worklist.size(); ++Idx) {
719     Loop *L2 = Worklist[Idx];
720     Worklist.append(L2->begin(), L2->end());
721   }
722 
723   while (!Worklist.empty())
724     Changed |= simplifyOneLoop(Worklist.pop_back_val(), Worklist, DT, LI, SE,
725                                AC, MSSAU, PreserveLCSSA);
726 
727   // Changing exit conditions for blocks may affect exit counts of this loop and
728   // any of its parents, so we must invalidate the entire subtree if we've made
729   // any changes. Do this here rather than in simplifyOneLoop() as the top-most
730   // loop is going to be the same for all child loops.
731   if (Changed && SE)
732     SE->forgetTopmostLoop(L);
733 
734   return Changed;
735 }
