785 /// runOnFunction - Run down all loops in the CFG (recursively, but we could do
786 /// it in any convenient order) inserting preheaders.
787 ///
788 bool LoopSimplify::runOnFunction(Function &F) {
789   bool Changed = false;
790   LoopInfo *LI = &getAnalysis<LoopInfoWrapperPass>().getLoopInfo();
791   DominatorTree *DT = &getAnalysis<DominatorTreeWrapperPass>().getDomTree();
792   auto *SEWP = getAnalysisIfAvailable<ScalarEvolutionWrapperPass>();
793   ScalarEvolution *SE = SEWP ? &SEWP->getSE() : nullptr;
794   AssumptionCache *AC =
795       &getAnalysis<AssumptionCacheTracker>().getAssumptionCache(F);
796   MemorySSA *MSSA = nullptr;
797   std::unique_ptr<MemorySSAUpdater> MSSAU;
798   auto *MSSAAnalysis = getAnalysisIfAvailable<MemorySSAWrapperPass>();
799   if (MSSAAnalysis) {
800     MSSA = &MSSAAnalysis->getMSSA();
801     MSSAU = std::make_unique<MemorySSAUpdater>(MSSA);
802   }
803 
804   bool PreserveLCSSA = mustPreserveAnalysisID(LCSSAID);
805 
806   // Simplify each loop nest in the function.
807   for (auto *L : *LI)
808     Changed |= simplifyLoop(L, DT, LI, SE, AC, MSSAU.get(), PreserveLCSSA);
809 
810 #ifndef NDEBUG
811   if (PreserveLCSSA) {
812     bool InLCSSA = all_of(
813         *LI, [&](Loop *L) { return L->isRecursivelyLCSSAForm(*DT, *LI); });
814     assert(InLCSSA && "LCSSA is broken after loop-simplify.");
815   }
816 #endif
817   return Changed;
818 }
